```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input buffer
    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);

    NetworkPacket packet;

    // Read packet_id using read function
    adaptor.read(&packet.packet_id);

    // Read username using prefixed adaptor
    packet.username = adaptor.read<std::string>();

    // Read score count and use read_container to read scores vector
    uint32_t score_count;
    adaptor.read(&score_count);
    adaptor.read_container(packet.scores, score_count);

    // Read metadata as null-terminated string using null_terminated adaptor
    packet.metadata = adaptor.read<std::string>();

    // Skip remaining padding bytes if any
    size_t bytes_read = sizeof(packet.packet_id) + 
                       (packet.username.size() + sizeof(uint32_t)) + // username length prefix + content
                       (sizeof(uint32_t) + score_count * sizeof(uint32_t)) + // score count + scores
                       (packet.metadata.size() + 1); // metadata + null terminator

    if (bytes_read < buffer.size()) {
        adaptor.skip(buffer.size() - bytes_read);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input buffer
    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);

    PacketInfo info;

    // Use span() to get zero-copy view of packet_id
    info.packet_id = *adaptor.span<uint32_t>(1)[0];

    // Read username using prefixed adaptor
    info.username = adaptor.read<std::string_view>();

    // Read score count and skip scores vector
    uint32_t score_count;
    adaptor.read(&score_count);
    adaptor.skip(score_count * sizeof(uint32_t));

    return info;
}
```

## Key Implementation Points:

1. **deserialize_packet function:**
   - Creates `buffer_adaptor` from the input buffer
   - Uses `read()` function to read `packet_id`
   - Uses `prefixed` adaptor (via `read<std::string>()`) to read username
   - Reads score count then uses `read_container()` to populate scores vector
   - Uses `null_terminated` adaptor (via `read<std::string>()`) for metadata
   - Calculates and skips remaining padding bytes

2. **extract_packet_info function:**
   - Uses `span()` for zero-copy access to packet_id
   - Uses `prefixed` adaptor (via `read<std::string_view>()`) for username
   - Reads score count then skips scores vector using `skip()`
   - Returns only required information without full deserialization

3. **Proper use of Hexi library functions:**
   - Correctly uses `buffer_adaptor` constructor
   - Properly chains read operations using the adaptor
   - Handles different data types and adaptors appropriately
   - Implements padding handling correctly

The implementation follows all the assessment objectives and properly utilizes the Hexi library functions as specified in the reference materials.

