#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create a buffer_adaptor for the buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Check available space using buffer_adaptor's size() method
    auto available_space = adaptor.size();

    // Calculate required space: sizeof(header) + items.size() * sizeof(uint32_t)
    auto required_space = sizeof(header) + items.size() * sizeof(uint32_t);

    // Compare available space with required space
    if (available_space < required_space) {
        return false; // Insufficient space
    }

    // Get the write pointer using buffer_adaptor's write_ptr() method
    auto* write_ptr = adaptor.write_ptr();

    // Write the header to the write pointer location
    *reinterpret_cast<uint32_t*>(write_ptr) = header;

    // Advance write pointer past the header
    adaptor.advance_write(sizeof(header));

    // Write the items vector using write_container function
    // Create a binary_stream for writing
    hexi::binary_stream stream(adaptor, 0);

    // Use operator<< to write the container (which internally uses write_container)
    stream << items;

    return true; // Write successful
}
